export {
  createDataTableQueryOptions,
  type InfiniteQueryMeta,
  type InfiniteQueryResponse,
} from "./create-query-options";
export { getFacetedMinMaxValues, getFacetedUniqueValues } from "./faceted";
export {
  facetMetadataSchema,
  type BaseChartSchema,
  type FacetMetadataSchema,
} from "./types";

import { infiniteQueryOptions, keepPreviousData } from "@tanstack/react-query";
import SuperJSON from "superjson";
import type { BaseChartSchema, FacetMetadataSchema } from "./types";

export type InfiniteQueryMeta<TMeta = Record<string, unknown>> = {
  totalRowCount: number;
  filterRowCount: number;
  chartData: BaseChartSchema[];
  facets: Record<string, FacetMetadataSchema>;
  metadata?: TMeta;
};

export type InfiniteQueryResponse<TData, TMeta = unknown> = {
  data: TData;
  meta: InfiniteQueryMeta<TMeta>;
  prevCursor: number | null;
  nextCursor: number | null;
};

function getBaseUrl() {
  if (typeof window !== "undefined") return "";
  if (process.env.VERCEL_URL) return `https://${process.env.VERCEL_URL}`;
  return `http://localhost:${process.env.PORT ?? 3000}`;
}

/**
 * Factory for creating infinite query options for data tables.
 *
 * Parametrizes the query key prefix, API endpoint, and serializer —
 * everything else (pagination, caching, SuperJSON) is shared.
 */
export function createDataTableQueryOptions<TData, TMeta>(config: {
  queryKeyPrefix: string;
  apiEndpoint: string;
  searchParamsSerializer: (search: Record<string, unknown>) => string;
}) {
  return (search: Record<string, unknown>) => {
    const cursor = search.cursor as Date | undefined;
    const initialCursor = cursor?.getTime?.() ?? Date.now();

    // Normalize empty arrays to null for consistent serialization
    const normalized: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(search)) {
      if (Array.isArray(value) && value.length === 0) {
        normalized[key] = null;
      } else {
        normalized[key] = value;
      }
    }

    const stableKey = config.searchParamsSerializer({
      ...normalized,
      uuid: null,
      live: null,
      cursor: null,
      direction: null,
    });

    return infiniteQueryOptions({
      queryKey: [config.queryKeyPrefix, stableKey],
      queryFn: async ({ pageParam }) => {
        const cursorDate = new Date(pageParam.cursor);
        const direction = pageParam.direction as "next" | "prev" | undefined;
        const serialize = config.searchParamsSerializer({
          ...search,
          cursor: cursorDate,
          direction,
          uuid: null,
          live: null,
        });
        const response = await fetch(
          `${getBaseUrl()}${config.apiEndpoint}${serialize}`,
        );
        const json = await response.json();
        return SuperJSON.parse<InfiniteQueryResponse<TData, TMeta>>(json);
      },
      initialPageParam: { cursor: initialCursor, direction: "next" },
      getPreviousPageParam: (firstPage) => {
        if (!firstPage.prevCursor) return null;
        return { cursor: firstPage.prevCursor, direction: "prev" };
      },
      getNextPageParam: (lastPage) => {
        if (!lastPage.nextCursor) return null;
        return { cursor: lastPage.nextCursor, direction: "next" };
      },
      refetchOnWindowFocus: false,
      placeholderData: keepPreviousData,
      staleTime: 1000 * 60 * 5,
    });
  };
}

import type { RowModel, Table as TTable } from "@tanstack/react-table";
import type { FacetMetadataSchema } from "./types";

/**
 * Drop-in replacement for TanStack's `getFacetedUniqueValues` that flattens
 * array column values. The built-in version treats `["a", "b"]` as one unique
 * value; this version counts each item individually.
 *
 * Works for both array and non-array columns.
 */
export function getFacetedUniqueValuesFlattened<TData>(): (
  table: TTable<TData>,
  columnId: string,
) => () => Map<unknown, number> {
  return (table, columnId) => {
    return () => {
      const facetedRowModel: RowModel<TData> | undefined = table
        .getColumn(columnId)
        ?.getFacetedRowModel();
      if (!facetedRowModel) return new Map();

      const counts = new Map<unknown, number>();
      for (const row of facetedRowModel.flatRows) {
        const value = row.getValue(columnId);
        if (Array.isArray(value)) {
          for (const item of value) {
            counts.set(item, (counts.get(item) ?? 0) + 1);
          }
        } else if (value != null) {
          counts.set(value, (counts.get(value) ?? 0) + 1);
        }
      }
      return counts;
    };
  };
}

export function getFacetedUniqueValues<TData>(
  facets?: Record<string, FacetMetadataSchema>,
) {
  return (_: TTable<TData>, columnId: string): Map<string, number> => {
    return new Map(
      facets?.[columnId]?.rows?.map(({ value, total }) => [value, total]) || [],
    );
  };
}

export function getFacetedMinMaxValues<TData>(
  facets?: Record<string, FacetMetadataSchema>,
) {
  return (_: TTable<TData>, columnId: string): [number, number] | undefined => {
    const min = facets?.[columnId]?.min;
    const max = facets?.[columnId]?.max;
    if (typeof min === "number" && typeof max === "number") return [min, max];
    if (typeof min === "number") return [min, min];
    if (typeof max === "number") return [max, max];
    return undefined;
  };
}
